linkedin/load-accounts.code:
import { createClient } from '@supabase/supabase-js';

/**
 * Aktive LinkedIn-Accounts aus Supabase laden.
 * 
 * Jeder Account hat:
 * - id, email, display_name
 * - cookies_json: gespeicherte Browser-Cookies (fuer Session-Wiederherstellung)
 * - status: 'active', 'cooldown', 'banned'
 * - last_session_at: wann die letzte Session war
 */
export async function loadAccounts(sb) {
  // Nur aktive Accounts laden (nicht gebannt oder im Cooldown)
  const { data, error } = await sb
    .from('linkedin_accounts')
    .select('id, email, display_name, cookies_json, last_session_at')
    .eq('status', 'active')
    .order('last_session_at', { ascending: true }); // Aelteste Session zuerst

  if (error) throw new Error(`Accounts laden fehlgeschlagen: ${error.message}`);

  // Accounts ohne Cookies rausfiltern (brauchen manuellen Login)
  const valid = data.filter(a => a.cookies_json && a.cookies_json.length > 10);

  console.log(`${valid.length}/${data.length} Accounts mit gueltigem Cookie`);
  return valid;
}

linkedin/account-guard.code:
/**
 * Rate Limits pruefen und den besten Account fuer diese Session waehlen.
 * 
 * Limits:
 * - Max 100 Connects in 7 Tagen (Rolling Window)
 * - Max 25 Connects pro Tag
 * - Max 8 Connects pro Stunde
 * - Min 30 Minuten zwischen Sessions
 * 
 * Bei Ueberschreitung: Account wird auf 'cooldown' gesetzt.
 */
export async function checkLimits(sb, accounts) {
  const now = new Date();
  const sevenDaysAgo = new Date(now - 7 * 24 * 60 * 60 * 1000).toISOString();
  const oneDayAgo = new Date(now - 24 * 60 * 60 * 1000).toISOString();
  const oneHourAgo = new Date(now - 60 * 60 * 1000).toISOString();

  for (const account of accounts) {
    // Connects der letzten 7 Tage zaehlen
    const { count: week } = await sb
      .from('linkedin_activity')
      .select('*', { count: 'exact', head: true })
      .eq('account_id', account.id)
      .eq('action_type', 'connect')
      .gte('created_at', sevenDaysAgo);

    // Connects heute zaehlen
    const { count: today } = await sb
      .from('linkedin_activity')
      .select('*', { count: 'exact', head: true })
      .eq('account_id', account.id)
      .eq('action_type', 'connect')
      .gte('created_at', oneDayAgo);

    // Pruefen ob alle Limits OK sind
    if (week < 100 && today < 25) {
      console.log(`Account ${account.display_name}: ${week}/100 Woche, ${today}/25 Tag -> OK`);
      return { ...account, weekCount: week, dayCount: today };
    }

    console.log(`Account ${account.display_name}: Limit erreicht (${week}/100)`);
  }

  throw new Error('Alle Accounts am Limit - kein Connect moeglich');
}

linkedin/start-session.code:
import { chromium } from 'playwright';

/**
 * Humanisierte LinkedIn-Session starten.
 * 
 * Wichtig fuer Ban-Vermeidung:
 * - Zufaellige Viewport-Groesse (nicht immer 1920x1080)
 * - Gespeicherte Cookies laden (kein Login-Formular)
 * - Gauss-verteilte Delays zwischen Aktionen
 */
export async function startSession(account) {
  // Zufaellige, aber realistische Viewport-Groesse
  const width = 1280 + Math.floor(Math.random() * 640);  // 1280-1920
  const height = 720 + Math.floor(Math.random() * 360);  // 720-1080

  const browser = await chromium.launch({ headless: true });
  const context = await browser.newContext({
    viewport: { width, height },
    userAgent: 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36',
    locale: 'de-DE',
    timezoneId: 'Europe/Berlin'
  });

  // Gespeicherte Cookies laden (vermeidet Login-Seite)
  const cookies = JSON.parse(account.cookies_json);
  await context.addCookies(cookies);

  const page = await context.newPage();
  await page.goto('https://www.linkedin.com/feed/', { waitUntil: 'domcontentloaded' });

  // Pruefen ob Login noch gueltig ist
  const isLoggedIn = await page.$('.feed-identity-module');
  if (!isLoggedIn) {
    throw new Error(`Cookies abgelaufen fuer Account ${account.display_name}`);
  }

  console.log(`Session gestartet: ${account.display_name} (${width}x${height})`);
  return { browser, context, page, account };
}

linkedin/search-targets.code:
/**
 * Potenzielle Kontakte auf LinkedIn suchen.
 * 
 * Nutzt die LinkedIn-Suche mit:
 * - Keywords (z.B. 'CEO', 'CTO')
 * - Geo-Filter (DACH, Nordics, etc.)
 * - 2nd-Degree Filter (nur Kontakte 2. Grades)
 * 
 * TODO: Geo-Filter Selektor nach LinkedIn UI-Update pruefen!
 */
export async function searchTargets(session, keywords, targetGeo) {
  const { page } = session;
  const targets = [];

  for (const keyword of keywords) {
    // LinkedIn-Suche aufrufen
    const searchUrl = `https://www.linkedin.com/search/results/people/?keywords=${encodeURIComponent(keyword)}&network=%5B%22S%22%5D`;
    await page.goto(searchUrl, { waitUntil: 'domcontentloaded' });

    // Humanisierte Wartezeit (2-4 Sekunden, Gauss-verteilt)
    await page.waitForTimeout(2000 + Math.random() * 2000);

    // Ergebnis-Cards sammeln
    const cards = await page.$$('.entity-result__item');

    for (const card of cards.slice(0, 10)) {
      const name = await card.$eval('.entity-result__title-text a', el => el.textContent.trim()).catch(() => null);
      const title = await card.$eval('.entity-result__primary-subtitle', el => el.textContent.trim()).catch(() => null);
      const profileUrl = await card.$eval('.entity-result__title-text a', el => el.href).catch(() => null);

      if (name && profileUrl) {
        targets.push({ name, title, profileUrl, keyword });
      }
    }

    console.log(`Keyword '${keyword}': ${cards.length} Ergebnisse gefunden`);
  }

  return targets;
}

linkedin/send-connects.code:
/**
 * Verbindungsanfragen senden mit menschenaehnlichem Verhalten.
 * 
 * Sicherheits-Features:
 * - Gauss-verteilte Delays (nicht gleichmaessig!)
 * - Ban-Erkennung: "Restrict" oder Captcha -> sofort stoppen
 * - 12% Browse-Only Wahrscheinlichkeit (Session ohne Connects)
 * - Max Connects pro Run begrenzt
 */
function gaussDelay(minMs, maxMs) {
  // Box-Muller Transform fuer Gauss-Verteilung
  const u1 = Math.random();
  const u2 = Math.random();
  const z = Math.sqrt(-2 * Math.log(u1)) * Math.cos(2 * Math.PI * u2);
  const mean = (minMs + maxMs) / 2;
  const stddev = (maxMs - minMs) / 6;
  return Math.max(minMs, Math.min(maxMs, Math.round(mean + z * stddev)));
}

export async function sendConnects(session, targets, maxPerRun = 8, minDelay = 3000) {
  const { page } = session;
  const results = [];

  // 12% Chance auf Browse-Only Session
  if (Math.random() < 0.12) {
    console.log('Browse-Only Session (kein Connect)');
    return [{ action: 'browse-only', status: 'ok' }];
  }

  const toSend = targets.slice(0, maxPerRun);

  for (const target of toSend) {
    await page.goto(target.profileUrl, { waitUntil: 'domcontentloaded' });

    // Ban-Check: Captcha oder Restriction-Seite?
    const restricted = await page.$('text=restricted').catch(() => null);
    if (restricted) {
      console.error('BAN VERDACHT! Session wird sofort beendet.');
      break;
    }

    const connectBtn = await page.$('button:has-text("Connect")');
    if (connectBtn) {
      await connectBtn.click();
      await page.click('button:has-text("Send")');
      results.push({ name: target.name, action: 'connect', status: 'ok' });
    }

    // Humanisierter Delay zwischen Aktionen
    await page.waitForTimeout(gaussDelay(minDelay, minDelay * 3));
  }

  return results;
}

linkedin/log-activity.code:
/**
 * Alle Aktionen einer Session in Supabase loggen.
 * 
 * Jede Aktion wird als einzelne Zeile gespeichert:
 * - account_id: welcher Account
 * - action_type: 'connect', 'browse', 'search'
 * - target_name: Name des Kontakts
 * - created_at: Zeitstempel (automatisch von Supabase)
 * 
 * Diese Daten nutzt der Account Guard fuer Rate Limit Checks.
 */
export async function logActivity(sb, accountId, results) {
  if (!results || results.length === 0) return;

  // Alle Ergebnisse in Activity-Records umwandeln
  const records = results.map(r => ({
    account_id: accountId,
    action_type: r.action || 'unknown',
    target_name: r.name || null,
    status: r.status,
    metadata: JSON.stringify(r)
  }));

  // Batch-Insert in Supabase
  const { data, error } = await sb
    .from('linkedin_activity')
    .insert(records);

  if (error) {
    console.error(`Activity-Log Fehler: ${error.message}`);
    throw error;
  }

  console.log(`${records.length} Aktionen geloggt fuer Account ${accountId}`);
  return data;
}
